/* GENERATED by dev/tune_fixed.py (atan, n = 4, r = 20) -- do not
   edit directly; retune or re-emit with
       python3 dev/tune_fixed.py atan 4 --pin 20 --emit */

#include "flint.h"
#include "longlong.h"
#include "mpn_extras.h"
